    // C: size_t sz = luaO_str2num(s, s2v(L->top.p));
    // C: if (sz != 0) api_incr_top(L);
    // TODO(port): luaO_str2num not yet translated; push result if successful.
    match state.str_to_num(s) {
        Some((val, consumed)) => {
            state.push(val);
            consumed
        }
        None => 0,
    }
}

